import{_ as a,o as i,i as t,ad as s}from"./chunks/framework.Cq4hg8jX.js";const S=JSON.parse('{"title":"SSR 與正式環境","description":"為什麼伺服器端渲染不需要任何特殊處理，以及在開發與正式環境建置中可以對 PikaCSS 有什麼預期。","frontmatter":{"title":"SSR 與正式環境","description":"為什麼伺服器端渲染不需要任何特殊處理，以及在開發與正式環境建置中可以對 PikaCSS 有什麼預期。","relatedPackages":["@pikacss/unplugin-pikacss","@pikacss/integration","@pikacss/nuxt-pikacss"],"relatedSources":["packages/unplugin/src/index.ts","packages/integration/src/ctx.ts","packages/nuxt/src/index.ts"],"category":"integrations","order":24,"translation":{"sourceFile":"docs/integrations/ssr-and-production.md","sourceCommit":"36ab046b5f27060274a79d160c9b43606652d780","sourceBlob":"5df849173e8baab909992f60f22de00abc1d63d7"}},"headers":[],"relativePath":"zh-tw/integrations/ssr-and-production.md","filePath":"zh-tw/integrations/ssr-and-production.md"}'),r={name:"zh-tw/integrations/ssr-and-production.md"};function n(o,e,c,d,l,p){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="ssr-production" tabindex="-1">SSR 與正式環境 <a class="header-anchor" href="#ssr-production" aria-label="Permalink to “SSR 與正式環境”">​</a></h1><p>PikaCSS 的輸出是一個在建置時期產生的靜態 CSS 檔案。光是這一點，就回答了大多數關於 SSR 與正式環境的問題。</p><h2 id="ssr-ssg-and-streaming-just-work" tabindex="-1">SSR、SSG 與串流都能直接運作 <a class="header-anchor" href="#ssr-ssg-and-streaming-just-work" aria-label="Permalink to “SSR、SSG 與串流都能直接運作”">​</a></h2><p>這裡沒有執行階段的樣式注入，也沒有需要清空的 style registry：</p><ul><li>每一次 <code>pika()</code> 呼叫都會在建置期間替換成 class 名稱的字串常值；元件在伺服器上會直接渲染成純字串，就和在瀏覽器裡一樣。</li><li>所有產生出來的樣式都放在同一個 CSS 檔案裡（預設是 <code>pika.gen.css</code>）。<code>import &#39;pika.css&#39;</code> 這個 specifier 會解析到該檔案，而你的打包工具會像處理其他任何樣式表匯入一樣處理它。</li></ul><p>因此，伺服器端渲染、靜態網站產生，以及串流回應都不需要 PikaCSS 特有的處理：只要你的環境能提供一般匯入的樣式表，就能提供 PikaCSS。這裡沒有 <code>extractCriticalToChunks</code>、沒有 <code>ServerStyleSheet</code>，也不會有任何由樣式造成的 hydration 不一致問題。</p><p>至於 Nuxt，<code>@pikacss/nuxt-pikacss</code> 模組會註冊一個 Nuxt 外掛範本，它唯一的工作就是 <code>import &quot;pika.css&quot;</code>，除此之外不會往伺服器或用戶端的執行環境加入任何東西。詳情請見 <a href="/zh-tw/integrations/nuxt.html">Nuxt</a>。</p><h2 id="production-builds" tabindex="-1">正式環境建置 <a class="header-anchor" href="#production-builds" aria-label="Permalink to “正式環境建置”">​</a></h2><p>在建置模式下，外掛會先一次掃描所有符合 <code>scan.include</code> 的檔案，收集每一處 <code>pika()</code> 的使用，並在打包繼續進行之前寫出完整的 CSS 檔案。輸出內容包含：</p><ul><li><code>@layer</code> 順序宣告，</li><li>preflight（已剔除未使用的變數與關鍵影格），</li><li>去除重複後的原子 class，其大小取決於不重複的宣告數量，而非呼叫位置的數量（詳情請見 <a href="/zh-tw/getting-started/how-pikacss-generates-css.html">PikaCSS 如何產生 CSS</a>）。</li></ul><p>結果會經過你打包工具正常的 CSS 流程（壓縮、雜湊，以及程式碼分割），PikaCSS 不會對它做任何更動。</p><h2 id="what-triggers-a-reload-in-dev" tabindex="-1">開發時什麼會觸發重新載入 <a class="header-anchor" href="#what-triggers-a-reload-in-dev" aria-label="Permalink to “開發時什麼會觸發重新載入”">​</a></h2><p>開發伺服器會在以下情況重新建立引擎（並重新產生兩個輸出檔案）：</p><ul><li><strong>設定檔變更時。</strong> PikaCSS 會監看解析後的 <code>pika.config.*</code> 檔案；內容一有變更，就會重新載入設定並重建引擎。</li><li><strong>設定相依（config dependency）變更時。</strong> 會載入外部檔案的外掛，會透過 <code>engine.addConfigDependency(path)</code> 註冊這些檔案，例如 <a href="/zh-tw/official-plugins/design-tokens.html">@pikacss/plugin-design-tokens</a> 會註冊它的 token 來源檔案。這些路徑的監看方式和設定檔相同。</li></ul><p>這兩條路徑都仰賴打包工具的檔案監看器（esbuild 是例外，它沒有以監看為基礎的重新載入路徑）。一般的原始碼編輯不會重新建立引擎，只會新增或更新受影響檔案的使用情形，而產生出來的檔案只有在解析後的樣式真的變更時才會重新寫出。</p><h2 id="type-level-performance" tabindex="-1">型別層級的效能 <a class="header-anchor" href="#type-level-performance" aria-label="Permalink to “型別層級的效能”">​</a></h2><p>產生出來的 <code>pika.gen.ts</code> 大小（自動完成的聯集型別、預覽多載）會隨著你的專案成長。TypeScript 型別系統的成本，會由一套位於儲存庫內的基準測試工具（<code>scripts/type-bench/</code>）追蹤，它會測量不同使用規模與 TS 版本下的檢查時間、型別具現化的數量，以及 IDE 延遲，因此型別效能的退步是實際測量出來的，而不是用猜的。我們沒有公布任何絕對數字，因為這些數字高度取決於專案的形態與硬體。</p><h2 id="next" tabindex="-1">下一步 <a class="header-anchor" href="#next" aria-label="Permalink to “下一步”">​</a></h2><ul><li><a href="/zh-tw/getting-started/how-pikacss-generates-css.html">PikaCSS 如何產生 CSS</a>：輸出檔案背後的執行模型。</li><li><a href="/zh-tw/integrations/unplugin.html">Unplugin</a>：包含 <code>scan</code>、<code>tsCodegen</code>，以及 <code>cssCodegen</code> 的建置工具選項。</li><li><a href="/zh-tw/integrations/nuxt.html">Nuxt</a>：Nuxt 模組的自動接線。</li></ul>',19)])])}const u=a(r,[["render",n]]);export{S as __pageData,u as default};
